    "solutionCode": "/**\n * @param {number[][]} mat\n * @return {number[][]}\n */\nvar updateMatrix = function (mat) {\n    let m = mat.length;\n    let n = mat[0].length;\n    let queue = [];\n\n    // Step 1: Put all 0s into queue\n    // and mark 1s as Infinity\n    for (let i = 0; i < m; i++) {\n        for (let j = 0; j < n; j++) {\n            if (mat[i][j] === 0) {\n                queue.push([i, j]);\n            } else {\n                mat[i][j] = Infinity;\n            }\n        }\n    }\n\n    // 4 directions\n    let dirs = [[1, 0], [-1, 0],[0, 1],[0, -1]];\n\n    // Step 2: BFS\n    while (queue.length > 0) {\n        let [r, c] = queue.shift();\n\n        for (let [dr, dc] of dirs) {\n            let nr = r + dr;\n            let nc = c + dc;\n\n            // boundary check\n            if (nr >= 0 && nr < m &&\n                nc >= 0 && nc < n\n            ) {\n                // If shorter distance found\n                if (mat[nr][nc] > mat[r][c] + 1) {\n                    mat[nr][nc] = mat[r][c] + 1;\n                    queue.push([nr, nc]);\n                }\n            }\n        }\n    }\n\n    return mat;\n};",
