    "solutionCode": "function solve(input) {\n  const mat = input.nums;\n  const { row1, col1, row2, col2 } = input;\n  const obj = new NumMatrix(mat);\n  return obj.sumRegion(row1, col1, row2, col2);\n}\n\n/**\n * @param {number[][]} matrix\n */\nvar NumMatrix = function (matrix) {\n    let rows = matrix.length;\n    let cols = matrix[0].length;\n\n    // Extra row and column\n    this.prefix = Array(rows + 1)\n        .fill(0)\n        .map(() => Array(cols + 1).fill(0));\n\n    // Build prefix sum\n    for (let r = 0; r < rows; r++) {\n        for (let c = 0; c < cols; c++) {\n\n            this.prefix[r + 1][c + 1] =\n                matrix[r][c]\n                + this.prefix[r][c + 1]\n                + this.prefix[r + 1][c]\n                - this.prefix[r][c];\n        }\n    }\n};\n\n/** \n * @param {number} row1 \n * @param {number} col1 \n * @param {number} row2 \n * @param {number} col2\n * @return {number}\n */\nNumMatrix.prototype.sumRegion = function (row1, col1, row2, col2) {\n    return (\n        this.prefix[row2 + 1][col2 + 1]\n        - this.prefix[row1][col2 + 1]\n        - this.prefix[row2 + 1][col1]\n        + this.prefix[row1][col1]\n    );\n};\n\n/** \n * Your NumMatrix object will be instantiated and called as such:\n * var obj = new NumMatrix(matrix)\n * var param_1 = obj.sumRegion(row1,col1,row2,col2)\n */",
