    "solutionCode": "/**\n * @param {number[]} nums\n * @param {number} k\n * @return {number}\n */\nvar findPairs = function (nums, k) {\n    if (k < 0) return 0;\n    nums.sort((a, b) => a - b);\n    let left = 0;\n    let right = 1;\n    let count = 0;\n    while (right < nums.length) {\n        // avoid same index\n        if (left === right) {\n            right++;\n            continue;\n        }\n        let diff = nums[right] - nums[left];\n        if (diff < k) {\n            right++;\n        } else if (diff > k) {\n            left++;\n        } else {\n            count++;\n            left++;\n            // skip duplicates\n            while (\n                left < nums.length &&\n                nums[left] === nums[left - 1]\n            ) {\n                left++;\n            }\n        }\n    }\n    return count;\n};",
