    "solutionCode": "/**\n * @param {number} n\n * @return {number}\n */\nvar trailingZeroes = function(n) {\n    let count = 0;\n\n    // keep dividing by powers of 5\n    while (n >= 5) {\n        n = Math.floor(n / 5);\n        count += n;\n    }\n\n    return count;\n};",
