  "211": {
    "solutionCode": "/**\n * @param {string} s\n * @return {string}\n */\nvar longestDupSubstring = function(s) {\n    const mod = 2 ** 31 - 1;\n    const base = 26;\n\n    const n = s.length;\n\n    // convert char to number (a -> 0, b -> 1 ...)\n    const nums = Array.from(s, c => c.charCodeAt(0) - 97);\n\n    let left = 1, right = n - 1;\n    let start = -1;\n\n    const search = (len) => {\n        let hash = 0;\n        let power = 1;\n\n        for (let i = 0; i < len; i++) {\n            hash = (hash * base + nums[i]) % mod;\n            power = (power * base) % mod;\n        }\n\n        const seen = new Map();\n        seen.set(hash, [0]);\n\n        for (let i = 1; i <= n - len; i++) {\n            // rolling hash\n            hash = (hash * base - nums[i - 1] * power + nums[i + len - 1]) % mod;\n            if (hash < 0) hash += mod;\n\n            if (seen.has(hash)) {\n                for (let idx of seen.get(hash)) {\n                    if (s.substring(idx, idx + len) === s.substring(i, i + len)) {\n                        start = i;\n                        return true;\n                    }\n                }\n                seen.get(hash).push(i);\n            } else {\n                seen.set(hash, [i]);\n            }\n        }\n\n        return false;\n    };\n\n    while (left <= right) {\n        let mid = Math.floor((left + right) / 2);\n\n        if (search(mid)) {\n            left = mid + 1;\n        } else {\n            right = mid - 1;\n        }\n    }\n\n    return start === -1 ? \"\" : s.substring(start, start + left - 1);\n};",
    "entryFunction": "longestDupSubstring"
  }
